package dev.pinefield.crm;

import jakarta.servlet.http.Cookie;
import jakarta.servlet.http.HttpServletRequest;
import jakarta.servlet.http.HttpServletResponse;
import java.io.*;
import java.sql.*;
import java.util.*;
import java.net.URLDecoder;
import java.nio.charset.StandardCharsets;

public class CustomerLookupService {
    private static final String DB_URL = "jdbc:mysql://localhost:3306/appdb";
    private static final String DB_USER = "appuser";
    private static final String DB_PASS = "apppass";

    public void handle(HttpServletRequest request, HttpServletResponse response) throws IOException {
        response.setCharacterEncoding("UTF-8");
        response.setContentType("text/plain");
        try (PrintWriter writer = response.getWriter()) {
            String input = "";
            Cookie[] cookies = request.getCookies();
            if (cookies != null) {
                for (Cookie c : cookies) {
                    if ("q".equals(c.getName())) {
                        input = c.getValue();
                        break;
                    }
                }
            }

            try (Connection conn = DriverManager.getConnection(DB_URL, DB_USER, DB_PASS)) {
                String sql = "UPDATE customers SET name = 'checked' WHERE email = '" + input + "'";
                try (Statement st = conn.createStatement()) {
                    int changed = st.executeUpdate(sql);
                    writer.println(changed > 0 ? "updated" : "nochange");
                }
            } catch (SQLException e) {
                response.setStatus(500);
                writer.println("db_error");
            }
        }
    }
}

